    static double[] coordinates(SolarSystemEphemeris.Planet planet, double tau) {
        switch (planet) {
            case MERCURY:
                return computeLBR(MERCURY_L0, MERCURY_L1, MERCURY_L2, MERCURY_L3, MERCURY_L4, MERCURY_L5, MERCURY_B0, MERCURY_B1, MERCURY_B2, MERCURY_B3, MERCURY_B4, MERCURY_B5, MERCURY_R0, MERCURY_R1, MERCURY_R2, MERCURY_R3, MERCURY_R4, MERCURY_R5, tau);
            case VENUS:
                return computeLBR(VENUS_L0, VENUS_L1, VENUS_L2, VENUS_L3, VENUS_L4, VENUS_L5, VENUS_B0, VENUS_B1, VENUS_B2, VENUS_B3, VENUS_B4, VENUS_B5, VENUS_R0, VENUS_R1, VENUS_R2, VENUS_R3, VENUS_R4, VENUS_R5, tau);
            case MARS:
                return computeLBR(MARS_L0, MARS_L1, MARS_L2, MARS_L3, MARS_L4, MARS_L5, MARS_B0, MARS_B1, MARS_B2, MARS_B3, MARS_B4, MARS_B5, MARS_R0, MARS_R1, MARS_R2, MARS_R3, MARS_R4, MARS_R5, tau);
            case JUPITER:
                return computeLBR(JUPITER_L0, JUPITER_L1, JUPITER_L2, JUPITER_L3, JUPITER_L4, JUPITER_L5, JUPITER_B0, JUPITER_B1, JUPITER_B2, JUPITER_B3, JUPITER_B4, JUPITER_B5, JUPITER_R0, JUPITER_R1, JUPITER_R2, JUPITER_R3, JUPITER_R4, JUPITER_R5, tau);
            case SATURN:
                return computeLBR(SATURN_L0, SATURN_L1, SATURN_L2, SATURN_L3, SATURN_L4, SATURN_L5, SATURN_B0, SATURN_B1, SATURN_B2, SATURN_B3, SATURN_B4, SATURN_B5, SATURN_R0, SATURN_R1, SATURN_R2, SATURN_R3, SATURN_R4, SATURN_R5, tau);
            case URANUS:
                return computeLBR(URANUS_L0, URANUS_L1, URANUS_L2, URANUS_L3, URANUS_L4, URANUS_L5, URANUS_B0, URANUS_B1, URANUS_B2, URANUS_B3, URANUS_B4, URANUS_B5, URANUS_R0, URANUS_R1, URANUS_R2, URANUS_R3, URANUS_R4, URANUS_R5, tau);
            case NEPTUNE:
                return computeLBR(NEPTUNE_L0, NEPTUNE_L1, NEPTUNE_L2, NEPTUNE_L3, NEPTUNE_L4, NEPTUNE_L5, NEPTUNE_B0, NEPTUNE_B1, NEPTUNE_B2, NEPTUNE_B3, NEPTUNE_B4, NEPTUNE_B5, NEPTUNE_R0, NEPTUNE_R1, NEPTUNE_R2, NEPTUNE_R3, NEPTUNE_R4, NEPTUNE_R5, tau);
            default: throw new IllegalArgumentException("Unsupported planet " + planet);
        }
    }

    static double[] earthCoordinates(double tau) {
        return computeLBR(EARTH_L0, EARTH_L1, EARTH_L2, EARTH_L3, EARTH_L4, EARTH_L5, EARTH_B0, EARTH_B1, EARTH_B2, EARTH_B3, EARTH_B4, EARTH_B5, EARTH_R0, EARTH_R1, EARTH_R2, EARTH_R3, EARTH_R4, EARTH_R5, tau);
    }

    private static double[] computeLBR(
            double[][] l0, double[][] l1, double[][] l2, double[][] l3, double[][] l4, double[][] l5,
            double[][] b0, double[][] b1, double[][] b2, double[][] b3, double[][] b4, double[][] b5,
            double[][] r0, double[][] r1, double[][] r2, double[][] r3, double[][] r4, double[][] r5,
            double tau) {
        double L = sumPowerSeries(tau, l0, l1, l2, l3, l4, l5);
        double B = sumPowerSeries(tau, b0, b1, b2, b3, b4, b5);
        double R = sumPowerSeries(tau, r0, r1, r2, r3, r4, r5);
        return new double[]{L, B, R};
    }

    private static double sumPowerSeries(double tau, double[][]... series) {
        double total = 0.0;
        double tauPower = 1.0;
        for (double[][] terms : series) {
            double partial = 0.0;
            for (double[] term : terms) {
                partial += term[0] * Math.cos(term[1] + term[2] * tau);
            }
            total += partial * tauPower;
            tauPower *= tau;
        }
        return total;
    }
